-- ************************************** ANALYTICS.MV_ENCOUNTER_FINANCIAL_SUMMARY
CREATE MATERIALIZED VIEW ANALYTICS.MV_ENCOUNTER_FINANCIAL_SUMMARY
(
  CREATED_TIMESTAMP,
  CREATED_BY_NAME,
  UPDATED_TIMESTAMP,
  UPDATED_BY_NAME
)
AS
SELECT 
    e.ENCOUNTER_KEY,
    e.ENCOUNTER_ID,
    p.PATIENT_KEY,
    p.PATIENT_ID,
    pr.PROVIDER_KEY,
    pr.PROVIDER_ID,
    f.FACILITY_KEY,
    f.FACILITY_ID,
    pp.PAYER_PLAN_KEY,
    pp.PAYER_PLAN_ID,
    dd_admit.YEAR_NUMBER AS ENCOUNTER_YEAR,
    dd_admit.MONTH_NUMBER AS ENCOUNTER_MONTH,
    dd_admit.QUARTER_NUMBER AS ENCOUNTER_QUARTER,
    e.ENCOUNTER_TYPE,
    e.ENCOUNTER_CLASS,
    e.LENGTH_OF_STAY_DAYS,
    e.TOTAL_CHARGES_AMOUNT,
    e.TOTAL_PAYMENTS_AMOUNT,
    (e.TOTAL_CHARGES_AMOUNT - e.TOTAL_PAYMENTS_AMOUNT) AS WRITE_OFF_AMOUNT,
    e.READMISSION_FLAG,
    COUNT(DISTINCT ccl.CLAIM_LINE_KEY) AS CLAIM_LINE_COUNT,
    SUM(ccl.LINE_BILLED_AMOUNT) AS CLAIM_BILLED_AMOUNT,
    SUM(ccl.LINE_ALLOWED_AMOUNT) AS CLAIM_ALLOWED_AMOUNT,
    SUM(ccl.LINE_PAID_AMOUNT) AS CLAIM_PAID_AMOUNT,
    COUNT(DISTINCT fd.DIAGNOSIS_FACT_KEY) AS DIAGNOSIS_COUNT,
    COUNT(DISTINCT fp.PROCEDURE_FACT_KEY) AS PROCEDURE_COUNT
FROM ANALYTICS.FACT_ENCOUNTER e
LEFT JOIN ANALYTICS.DIM_PATIENT p ON e.PATIENT_KEY = p.PATIENT_KEY AND p.IS_CURRENT = TRUE
LEFT JOIN ANALYTICS.DIM_PROVIDER pr ON e.PROVIDER_KEY = pr.PROVIDER_KEY AND pr.IS_CURRENT = TRUE
LEFT JOIN ANALYTICS.DIM_FACILITY f ON e.FACILITY_KEY = f.FACILITY_KEY AND f.IS_CURRENT = TRUE
LEFT JOIN ANALYTICS.DIM_PAYER_PLAN pp ON e.PAYER_PLAN_KEY = pp.PAYER_PLAN_KEY AND pp.IS_CURRENT = TRUE
LEFT JOIN ANALYTICS.DIM_DATE dd_admit ON e.ADMIT_DATE_KEY = dd_admit.DATE_KEY
LEFT JOIN ANALYTICS.FACT_CLAIM_LINE ccl ON e.ENCOUNTER_KEY = ccl.CLAIM_KEY
LEFT JOIN ANALYTICS.FACT_DIAGNOSIS fd ON e.ENCOUNTER_KEY = fd.ENCOUNTER_KEY
LEFT JOIN ANALYTICS.FACT_PROCEDURE fp ON e.ENCOUNTER_KEY = fp.ENCOUNTER_KEY
GROUP BY 
    e.ENCOUNTER_KEY,
    e.ENCOUNTER_ID,
    p.PATIENT_KEY,
    p.PATIENT_ID,
    pr.PROVIDER_KEY,
    pr.PROVIDER_ID,
    f.FACILITY_KEY,
    f.FACILITY_ID,
    pp.PAYER_PLAN_KEY,
    pp.PAYER_PLAN_ID,
    dd_admit.YEAR_NUMBER,
    dd_admit.MONTH_NUMBER,
    dd_admit.QUARTER_NUMBER,
    e.ENCOUNTER_TYPE,
    e.ENCOUNTER_CLASS,
    e.LENGTH_OF_STAY_DAYS,
    e.TOTAL_CHARGES_AMOUNT,
    e.TOTAL_PAYMENTS_AMOUNT,
    e.READMISSION_FLAG;

